import{_ as a,c as e,o as t,a4 as l}from"./chunks/framework.C-PRJgRX.js";const m=JSON.parse('{"title":"代码质量评价标准","description":"","frontmatter":{},"headers":[{"level":2,"title":"编码规范","slug":"编码规范","link":"#编码规范","children":[]},{"level":2,"title":"可读性","slug":"可读性","link":"#可读性","children":[]},{"level":2,"title":"可维护性","slug":"可维护性","link":"#可维护性","children":[]},{"level":2,"title":"重复度","slug":"重复度","link":"#重复度","children":[]},{"level":2,"title":"可测试性","slug":"可测试性","link":"#可测试性","children":[]}],"relativePath":"accumulation/code-quality-standard.md","filePath":"accumulation/code-quality-standard.md","lastUpdated":1718763810000}'),i={name:"accumulation/code-quality-standard.md"},r=l('<h1 id="代码质量评价标准" tabindex="-1">代码质量评价标准 <a class="header-anchor" href="#代码质量评价标准" aria-label="Permalink to &quot;代码质量评价标准&quot;">​</a></h1><h2 id="编码规范" tabindex="-1">编码规范 <a class="header-anchor" href="#编码规范" aria-label="Permalink to &quot;编码规范&quot;">​</a></h2><p>主要包含是否遵守了最佳实践和团队编码规范，是否包含可能出问题的代码，以及可能存在安全的漏洞。编码规范有助于提高团队内协助的效率以及代码的可维护性。</p><h2 id="可读性" tabindex="-1">可读性 <a class="header-anchor" href="#可读性" aria-label="Permalink to &quot;可读性&quot;">​</a></h2><p>Code Review 是一个很好的测验代码可读性的手段。如果你的同事可以轻松地读懂你写的代码，那说明你的代码可读性很好；反之则说明你的代码可读性有待提高了。遵守编码规范也能让我们写出可读性更好的代码。</p><h2 id="可维护性" tabindex="-1">可维护性 <a class="header-anchor" href="#可维护性" aria-label="Permalink to &quot;可维护性&quot;">​</a></h2><p>代码的可维护性是由很多因素协同作用的结果。代码的可读性好、简洁、可扩展性好，就会使得代码易维护；更细化地讲，如果代码分层清晰、模块化好、高内聚低耦合、遵从基于接口而非实现编程的设计原则等等，那就可能意味着代码易维护。除此之外，代码的易维护性还跟项目代码量的多少、业务的复杂程度、利用到的技术的复杂程度、文档是否全面等诸多因素有关。</p><h2 id="重复度" tabindex="-1">重复度 <a class="header-anchor" href="#重复度" aria-label="Permalink to &quot;重复度&quot;">​</a></h2><p>遵守 Don’t Repeat Yourself 原则，尽量减少重复代码的编写，复用已有的代码。对项目定期进行代码重复度检测是一个很有意义的事，可以帮助开发人员发现冗余代码，进行代码抽象和重构。重复的代码一旦出错，意味着加倍的工作量和持续的不可控。如果代码中有大量的重复代码，就要考虑将重复的代码提取出来，封装成公共的方法或者组件。</p><h2 id="可测试性" tabindex="-1">可测试性 <a class="header-anchor" href="#可测试性" aria-label="Permalink to &quot;可测试性&quot;">​</a></h2><p>代码可测试性的好坏，同样可以反应代码质量的好坏。代码的可测试性差，比较难写单元测试，那基本上就能说明代码设计得有问题。</p>',11),o=[r];function n(d,c,s,h,u,_){return t(),e("div",null,o)}const f=a(i,[["render",n]]);export{m as __pageData,f as default};
